LEGACY_TOPIC_REDIRECTS = {"earth_planet": "our_planet_3", "continents_oceans": "our_planet_3", "map_globe": "our_planet_3", "water_cycle": "our_planet_3", "air_water_soil": "our_planet_3"}


def generate_world_class_3_topic_task(topic_id: str, used_questions: list[str] | None = None) -> dict:
    topic_id = LEGACY_TOPIC_REDIRECTS.get(topic_id, topic_id)
    tasks = TASK_DATA.get(topic_id, TASK_DATA["our_planet_3"])
    task = generate_unique_task(lambda: make_choice_task(*random.choice(tasks), topic_id), used_questions)
    task["topic"] = topic_id
    task["topic_title"] = WORLD_CLASS_3_TOPICS.get(topic_id, {}).get("title", "Окружающий мир 3 класс")
    return task
